        let (match_any, match_any_declaration) = &records["match_any_sync"];
        let mut wrong_adapter = match_any.clone();
        wrong_adapter.warp_match.as_mut().unwrap().adapter =
            WarpMatchAdapter::ProjectMaskDiscardPredicate;
